def log(msg):
    """Write to both log file and console."""
    with open(LOG_FILE, 'a', encoding='utf-8') as f:
        f.write(f"{msg}\n")
    print(msg)

# =============================================================================
# Main Analysis
# =============================================================================

if __name__ == "__main__":
    try:
        log("[START] Step 03: Merge Analysis Dataset")

        # =========================================================================
        # STEP 1: Load Input Data
        # =========================================================================
        # Expected: Cognitive test data and HCE rate data
        # Purpose: Merge these datasets and create centered predictors for regression

        log("[LOAD] Loading cognitive test data...")
        cognitive_df = pd.read_csv(RQ_DIR / "data" / "step01_cognitive_tests.csv")
        log(f"[LOADED] step01_cognitive_tests.csv ({len(cognitive_df)} rows, {len(cognitive_df.columns)} cols)")
        log(f"[INFO] Cognitive columns: {cognitive_df.columns.tolist()}")
        
        log("[LOAD] Loading HCE rate data...")
        hce_df = pd.read_csv(RQ_DIR / "data" / "step02_hce_rates.csv")
        log(f"[LOADED] step02_hce_rates.csv ({len(hce_df)} rows, {len(hce_df.columns)} cols)")
        log(f"[INFO] HCE columns: {hce_df.columns.tolist()}")

        # =========================================================================
        # STEP 2: Handle UID Column Case Differences
        # =========================================================================
        # Tool expects both DataFrames to have consistent column naming
        # cognitive_df has 'uid', hce_df has 'UID' - need to standardize
        
        log("[PREP] Standardizing UID column names...")
        # The merge_theta_cognitive function expects 'uid' in lowercase
        # So rename HCE data 'UID' to 'uid' to match cognitive data
        hce_df = hce_df.rename(columns={'UID': 'uid'})
        log(f"[PREP] HCE data now has uid column (was UID)")
        
        # Both datasets now have 'uid' in lowercase which the function expects
        # theta_df parameter will get hce_df, cognitive_df parameter gets cognitive_df

        # =========================================================================
        # STEP 3: Run Analysis Tool (Merge Datasets)
        # =========================================================================
        # Tool: merge_theta_cognitive
        # What it does: Inner join two DataFrames on uid column
        # Expected output: Combined dataset with both HCE rates and cognitive predictors

        log("[ANALYSIS] Running merge_theta_cognitive...")
        merged_df = merge_theta_cognitive(
            theta_df=hce_df,       # HCE rates (theta_df parameter used for first dataset)
            cognitive_df=cognitive_df,  # Cognitive tests
            how="inner"            # Inner join - only participants with both HCE and cognitive data
        )
        log("[DONE] Merge complete")
        log(f"[INFO] Merged dataset: {len(merged_df)} rows, {len(merged_df.columns)} cols")
        log(f"[INFO] Merged columns: {merged_df.columns.tolist()}")

        # =========================================================================
        # STEP 4: Center Continuous Predictors
        # =========================================================================
        # Center age, RAVLT, BVMT, RPM around sample means
        # Creates _c suffix versions for use in regression
        
        log("[ANALYSIS] Creating centered predictors...")
        
        # Continuous predictors to center
        predictors_to_center = ['age', 'ravlt_total', 'bvmt_total', 'rpm_score', 'ravlt_pct_ret', 'bvmt_pct_ret']

        # Mapping from raw name to centered name
        center_name_map = {
            'age': 'age_c',
            'ravlt_total': 'ravlt_c',
            'bvmt_total': 'bvmt_c',
            'rpm_score': 'rpm_c',
            'ravlt_pct_ret': 'ravlt_pct_ret_c',
            'bvmt_pct_ret': 'bvmt_pct_ret_c',
        }

        for predictor in predictors_to_center:
            if predictor in merged_df.columns:
                # Calculate sample mean
                sample_mean = merged_df[predictor].mean()
                # Create centered version
                centered_col = center_name_map[predictor]
                merged_df[centered_col] = merged_df[predictor] - sample_mean
                log(f"[CENTERED] {predictor} -> {centered_col} (mean={sample_mean:.3f})")
            else:
                log(f"[WARNING] Predictor {predictor} not found in merged data")

        # =========================================================================
        # STEP 5: Standardize Final Column Names
        # =========================================================================
        # Ensure final output has 'uid' (lowercase) for consistency with other RQ outputs
        
        log("[PREP] Standardizing final column names...")
        merged_df = merged_df.rename(columns={'UID': 'uid'})
        log(f"[PREP] Final columns: {merged_df.columns.tolist()}")

        # =========================================================================
        # STEP 6: Save Analysis Output
        # =========================================================================
        # This output will be used by: Step 04 hierarchical regression analysis

        log("[SAVE] Saving step03_analysis_dataset.csv...")
        # Output: step03_analysis_dataset.csv
        # Contains: Merged HCE + cognitive data with centered predictors ready for regression
        # Columns: uid, hce_rate, cognitive variables, and centered versions
        output_path = RQ_DIR / "data" / "step03_analysis_dataset.csv"
        merged_df.to_csv(output_path, index=False, encoding='utf-8')
        log(f"[SAVED] step03_analysis_dataset.csv ({len(merged_df)} rows, {len(merged_df.columns)} cols)")

        # =========================================================================
        # STEP 7: Run Validation Tool
        # =========================================================================
        # Tool: validate_data_columns
        # Validates: Required columns are present for downstream regression analysis
        # Required: uid, hce_rate, centered predictors, and sex

        log("[VALIDATION] Running validate_data_columns...")
        required_columns = ["uid", "hce_rate", "ravlt_c", "bvmt_c", "rpm_c", "age_c", "sex", "ravlt_pct_ret_c", "bvmt_pct_ret_c"]
        
        validation_result = validate_data_columns(
            df=merged_df,
            required_columns=required_columns
        )

        # Report validation results
        # Expected: All required columns present for regression analysis
        if isinstance(validation_result, dict):
            for key, value in validation_result.items():
                log(f"[VALIDATION] {key}: {value}")
        else:
            log(f"[VALIDATION] {validation_result}")

        # Additional data quality checks
        log("[VALIDATION] Additional quality checks...")
        log(f"[VALIDATION] Missing data summary:")
        for col in merged_df.columns:
            missing_count = merged_df[col].isnull().sum()
            if missing_count > 0:
                log(f"[VALIDATION]   {col}: {missing_count} missing ({missing_count/len(merged_df)*100:.1f}%)")
            else:
                log(f"[VALIDATION]   {col}: 0 missing")

        # Check centered variables have mean ~0
        log(f"[VALIDATION] Centered variable means (should be ~0):")
        centered_vars = ['age_c', 'ravlt_c', 'bvmt_c', 'rpm_c', 'ravlt_pct_ret_c', 'bvmt_pct_ret_c']
        for var in centered_vars:
            if var in merged_df.columns:
                mean_val = merged_df[var].mean()
                log(f"[VALIDATION]   {var}: mean={mean_val:.6f}")

        log("[SUCCESS] Step 03 complete")
        sys.exit(0)

    except Exception as e:
        log(f"[ERROR] {str(e)}")
        log("[TRACEBACK] Full error details:")
        with open(LOG_FILE, 'a', encoding='utf-8') as f:
            traceback.print_exc(file=f)
        traceback.print_exc()
        sys.exit(1)